#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    int prices[k];
    for (int i = 0; i < k; i++) {
        scanf("%d", &prices[i]);
    }
    qsort(prices, k, sizeof(int), compare);
    int count = 0;
    int i = 0;
    while (count < n && count < m && i < k) {
        count++;
        i++;
    }
    int sum = 0;
    for (int j = 0; j < i; j++) {
        sum += prices[j];
    }
    printf("%d\n", sum);
    return 0;
}

