const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let lines = [];
rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let [n, m, k] = lines[0].split(' ').map(Number);
    let prices = lines.slice(1, k + 1).map(Number).sort((a, b) => a - b);
    let sum = 0;
    for (let i = 0; i < Math.min(n, m); i++) {
        sum += prices[i];
    }
    console.log(sum);
});

